diff --git a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
index ee3cc950cdb5..5ffe68bd6da9 100644
--- a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
+++ b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
@@ -23,7 +23,7 @@ class AssumptionCache;
 struct SimplifyCFGOptions {
   int BonusInstThreshold = 1;
   bool ForwardSwitchCondToPhi = false;
-  bool ConvertSwitchRangeToICmp = false;
+  bool ConvertSwitchRangeToICmp = true;
   bool ConvertSwitchToLookupTable = false;
   bool NeedCanonicalLoop = true;
   bool HoistCommonInsts = false;
diff --git a/llvm/lib/Transforms/Scalar/SimplifyCFGPass.cpp b/llvm/lib/Transforms/Scalar/SimplifyCFGPass.cpp
index 60e5df08c6ef..b2d7d7af71ba 100644
--- a/llvm/lib/Transforms/Scalar/SimplifyCFGPass.cpp
+++ b/llvm/lib/Transforms/Scalar/SimplifyCFGPass.cpp
@@ -55,7 +55,7 @@ static cl::opt<bool> UserKeepLoops(
     cl::desc("Preserve canonical loop structure (default = true)"));

 static cl::opt<bool> UserSwitchRangeToICmp(
-    "switch-range-to-icmp", cl::Hidden, cl::init(false),
+    "switch-range-to-icmp", cl::Hidden, cl::init(true),
     cl::desc(
         "Convert switches into an integer range comparison (default = false)"));

diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..e70ff4b5f27b 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5824,6 +5824,85 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
     ContiguousCases = &CasesB;
     ContiguousDest = DestB;
     OtherDest = DestA;
+  } else if (HasDefault && !CasesB.empty()) {
+    // Neither set of case values is contiguous. If the switch condition has
+    // range metadata, check if the complement of the non-default cases
+    // within that range is a single contiguous range.
+    std::optional<ConstantRange> CondRange;
+    if (auto *Arg = dyn_cast<Argument>(SI->getCondition()))
+      CondRange = Arg->getRange();
+    else if (auto *I = dyn_cast<Instruction>(SI->getCondition()))
+      if (const MDNode *Ranges = I->getMetadata(LLVMContext::MD_range)) CondRange = getConstantRangeFromMetadata(*Ranges);
+
+    if (CondRange && !CondRange->isEmptySet() && !CondRange->isFullSet()) {
+      ConstantRange Compl = *CondRange;
+      for (auto *C : CasesB)
+        Compl = Compl.difference(ConstantRange(C->getValue()));
+
+      if (!Compl.isEmptySet() && !Compl.isFullSet()) {
+        APInt L = Compl.getLower(), U = Compl.getUpper();
+        if (L.ult(U)) {
+          // The complement forms a single contiguous range [L, U).
+          // Create: icmp ult (Cond - L), (U - L)
+          // True branch -> DestA (default, the complement dest)
+          // False branch -> DestB (non-default cases)
+          Constant *Offset = ConstantExpr::getNeg(
+              ConstantInt::get(SI->getContext(), L));
+          Constant *NumCases = ConstantInt::get(
+              SI->getContext(), U - L);
+          Value *Sub = SI->getCondition();
+          if (!Offset->isNullValue())
+            Sub = Builder.CreateAdd(Sub, Offset,
+                                    Sub->getName() + ".off");
+          Value *Cmp;
+          if (NumCases->isNullValue())
+            Cmp = ConstantInt::getTrue(SI->getContext());
+          else
+            Cmp = Builder.CreateICmpULT(Sub, NumCases, "switch");
+          Builder.CreateCondBr(Cmp, DestA, DestB);
+
+          // Update weights for the new branch.
+          if (hasBranchWeightMD(*SI)) {
+            SmallVector<uint64_t, 8> Weights;
+            getBranchWeights(SI, Weights);
+            if (Weights.size() == 1 + SI->getNumCases()) {
+              uint64_t TrueWeight = 0, FalseWeight = 0;
+              for (size_t I = 0, E = Weights.size(); I != E; ++I) {
+                if (SI->getSuccessor(I) == DestA)
+                  TrueWeight += Weights[I];
+                else
+                  FalseWeight += Weights[I];
+              }
+              while (TrueWeight > UINT32_MAX ||
+                     FalseWeight > UINT32_MAX) {
+                TrueWeight /= 2;
+                FalseWeight /= 2;
+              }
+              setFittedBranchWeights(
+                  *cast<BranchInst>(SI->getParent()->getTerminator()),
+                  {TrueWeight, FalseWeight}, /*IsExpected=*/false,
+                  /*ElideAllZero=*/true);
+            }
+          }
+
+          // Clean up PHI nodes in successors.
+          // DestA (default) has 1 incoming edge from this block (via default).
+          // After the transformation, it still has 1 edge. No cleanup needed.
+          // DestB (non-default cases) had CasesB.size() edges before.
+          // After, it has 1 edge. Remove CasesB.size() - 1 values.
+          for (auto BBI = DestB->begin(); isa<PHINode>(BBI); ++BBI) {
+            for (unsigned I = 0, E = CasesB.size() - 1; I != E; ++I)
+              cast<PHINode>(BBI)->removeIncomingValue(
+                  SI->getParent());
+          }
+
+          dropDebugUsers(*SI);
+          SI->eraseFromParent();
+          return true;
+        }
+      }
+    }
+    return false;
   } else
     return false;

